class Solution:
    def maximumJumps(self, nums, target):
        n = len(nums)
        NEG = float('-inf')
        memo = {}

        def solve(i):
            if i == n - 1:
                return 0
            if i in memo:
                return memo[i]
            memo[i] = NEG
            best = NEG
            for j in range(i + 1, n):
                if -target <= nums[j] - nums[i] <= target:
                    r = solve(j)
                    if r != NEG:
                        best = max(best, r + 1)
            memo[i] = best
            return best

        res = solve(0)
        return res if res != NEG else -1

