class Solution:
    def maximumJumps(self, nums, target):
        n = len(nums)
        NEG = float('-inf')
        dp = [NEG] * n
        dp[0] = 0
        for j in range(1, n):
            for i in range(j):
                if dp[i] != NEG and -target <= nums[j] - nums[i] <= target:
                    dp[j] = max(dp[j], dp[i] + 1)
        return dp[n - 1] if dp[n - 1] != NEG else -1

