var maximumJumps = function(nums, target) {
    const n = nums.length;
    const NEG = -Infinity;
    const dp = new Array(n).fill(NEG);
    dp[0] = 0;
    for (let j = 1; j < n; j++) {
        for (let i = 0; i < j; i++) {
            if (dp[i] !== NEG && nums[j] - nums[i] >= -target && nums[j] - nums[i] <= target) {
                dp[j] = Math.max(dp[j], dp[i] + 1);
            }
        }
    }
    return dp[n - 1] !== NEG ? dp[n - 1] : -1;
};
